SELECT 
FROM invest_budget
WHERE del_flag = '0'
AND budget_code LIKE CONCAT('%', #{budgetCode}, '%')
AND budget_name LIKE CONCAT('%', #{budgetName}, '%')
AND scheme_id = #{schemeId}
AND scheme_name LIKE CONCAT('%', #{schemeName}, '%')
AND plan_year = #{planYear}
AND budget_status = #{budgetStatus}
ORDER BY create_time DESC, budget_id DESC
